#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        cin >> a[i];
    }

    int best = INT_MIN;
    int current = 0;

    for (int i = 0; i < n; ++i) {
        current += a[i];
        if (current > best) {
            best = current;
        }
        if (current < 0) {
            current = 0;
        }
    }

    cout << best << '\n';

    return 0;
}
